        /// <summary>
        /// Returns a dictionary of headers safe for logging, with sensitive values redacted.
        /// </summary>
        public static Dictionary<string, string> SanitizeHeaders(IHeaderDictionary headers)
        {
            var sanitized = new Dictionary<string, string>();
            foreach (var header in headers)
            {
                if (SensitiveHeaders.Contains(header.Key))
                {
                    sanitized[header.Key] = "[REDACTED]";
                }
                else
                {
                    var value = header.Value.ToString();
                    sanitized[header.Key] = SanitizeGenericString(value);
                }
            }
            return sanitized;
        }

        /// <summary>
        /// Sanitizes a request body by redacting sensitive fields from JSON content.
        /// </summary>
        public static string SanitizeBody(string body, string contentType)
        {
            if (string.IsNullOrWhiteSpace(body))
                return "[EMPTY]";

            // Truncate excessively large bodies to prevent log flooding
            const int maxLogBodyLength = 4096;
            if (body.Length > maxLogBodyLength)
            {
                body = body.Substring(0, maxLogBodyLength) + $"...[TRUNCATED, total length: {body.Length}]";
            }

            if (contentType != null && contentType.Contains("application/json", StringComparison.OrdinalIgnoreCase))
            {
                try
                {
                    using var doc = JsonDocument.Parse(body.Length > maxLogBodyLength ? body.Substring(0, maxLogBodyLength) : body);
                    var sanitizedJson = SanitizeJsonElement(doc.RootElement);
                    return JsonSerializer.Serialize(sanitizedJson, new JsonSerializerOptions { WriteIndented = false });
                }
                catch (JsonException)
                {
                    // Not valid JSON; sanitize as generic string
                    return SanitizeGenericString(body);
                }
            }

            return SanitizeGenericString(body);
        }

        private static object SanitizeJsonElement(JsonElement element)
        {
            switch (element.ValueKind)
            {
                case JsonValueKind.Object:
                    var dict = new Dictionary<string, object>();
                    foreach (var property in element.EnumerateObject())
                    {
                        if (SensitiveBodyFields.Contains(property.Name))
                        {
                            dict[property.Name] = "[REDACTED]";
                        }
                        else
                        {
                            dict[property.Name] = SanitizeJsonElement(property.Value);
                        }
                    }
                    return dict;

                case JsonValueKind.Array:
                    var list = new List<object>();
                    foreach (var item in element.EnumerateArray())
                    {
                        list.Add(SanitizeJsonElement(item));
                    }
                    return list;

                case JsonValueKind.String:
                    var strValue = element.GetString();
                    return SanitizeGenericString(strValue ?? string.Empty);

                case JsonValueKind.Number:
                    if (element.TryGetInt64(out long longVal))
                        return longVal;
                    return element.GetDouble();

                case JsonValueKind.True:
                    return true;

                case JsonValueKind.False:
                    return false;

                default:
                    return null;
            }
        }

        /// <summary>
        /// Removes embedded tokens, JWTs, and emails from arbitrary strings.
        /// </summary>
        public static string SanitizeGenericString(string input)
        {
            if (string.IsNullOrEmpty(input))
                return input;

            var result = BearerTokenPattern.Replace(input, "Bearer [REDACTED]");
            result = JwtPattern.Replace(result, "[JWT_REDACTED]");
            result = EmailPattern.Replace(result, "[EMAIL_REDACTED]");
            return result;
        }

        /// <summary>
        /// Sanitizes SQL parameter values for logging — redacts anything that looks sensitive.
        /// </summary>
        public static string SanitizeSqlParameterValue(string paramName, object value)
        {
            if (value == null || value == DBNull.Value)
                return "NULL";

            var lowerName = paramName.ToLowerInvariant();
            if (lowerName.Contains("password") || lowerName.Contains("token") ||
                lowerName.Contains("secret") || lowerName.Contains("ssn") ||
                lowerName.Contains("credit") || lowerName.Contains("cvv") ||
                lowerName.Contains("pin") || lowerName.Contains("apikey"))
            {
                return "[REDACTED]";
            }

            var strValue = value.ToString();
            return SanitizeGenericString(strValue);
        }

        /// <summary>
        /// Extracts safe user context from claims (no tokens, only identifiers).
        /// </summary>
        public static Dictionary<string, string> GetSafeUserContext(ClaimsPrincipal principal)
        {
            var context = new Dictionary<string, string>();

            if (principal?.Identity == null || !principal.Identity.IsAuthenticated)
            {
                context["authenticated"] = "false";
                return context;
            }

            context["authenticated"] = "true";

            // Log only non-sensitive claims for correlation
            var safeClaimTypes = new HashSet<string>
            {
                ClaimTypes.NameIdentifier,
                "oid",   // Azure AD object ID
                "tid",   // Tenant ID
                "sub",
                ClaimTypes.Role
            };

            foreach (var claim in principal.Claims)
            {
                if (safeClaimTypes.Contains(claim.Type))
                {
                    // Use the short name for readability
                    var shortName = claim.Type.Contains("/")
                        ? claim.Type.Substring(claim.Type.LastIndexOf('/') + 1)
                        : claim.Type;
                    context[shortName] = claim.Value;
                }
            }

            return context;
        }

        /// <summary>
        /// Sanitizes exception messages to remove any embedded secrets or PII.
        /// </summary>
        public static string SanitizeExceptionMessage(string message)
        {
            if (string.IsNullOrEmpty(message))
                return message;

            var sanitized = SanitizeGenericString(message);

            // Redact connection strings that may appear in exceptions
            sanitized = Regex.Replace(
                sanitized,
                @"(Password|Pwd)\s*=\s*[^;]+",
                "$1=[REDACTED]",
                RegexOptions.IgnoreCase);

            sanitized = Regex.Replace(
                sanitized,
                @"(User Id|UID)\s*=\s*[^;]+",
                "$1=[REDACTED]",
                RegexOptions.IgnoreCase);

            return sanitized;
        }
    }

    /// <summary>
