    /// <summary>
    /// Secure database access layer with parameterized queries and safe logging.
    /// </summary>
    public class SecureDatabaseService
    {
        private readonly string _connectionString;
        private readonly ILogger _logger;

        public SecureDatabaseService(ILogger logger)
        {
            _logger = logger;

            // Connection string from secure configuration (Azure Key Vault / App Settings)
            _connectionString = Environment.GetEnvironmentVariable("SqlConnectionString")
                ?? throw new InvalidOperationException("Database connection string not configured.");
        }

        public async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string query,
            Dictionary<string, object> parameters,
            string correlationId)
        {
            // Log the query structure (not the raw values of sensitive params)
            var sanitizedParams = new Dictionary<string, string>();
            foreach (var param in parameters)
            {
                sanitizedParams[param.Key] = LogSanitizer.SanitizeSqlParameterValue(param.Key, param.Value);
            }

            _logger.LogInformation(
                "Executing database query. CorrelationId: {CorrelationId}, Query: {Query}, Parameters: {Parameters}",
                correlationId,
                query,
                JsonSerializer.Serialize(sanitizedParams));

            var results = new List<Dictionary<string, object>>();

            try
            {
                using var connection = new SqlConnection(_connectionString);
                await connection.OpenAsync();

                using var command = new SqlCommand(query, connection);
                command.CommandTimeout = 30;

                // Always use parameterized queries — never concatenate user input
                foreach (var param in parameters)
                {
                    command.Parameters.AddWithValue(param.Key, param.Value ?? DBNull.Value);
                }

                using var reader = await command.ExecuteReaderAsync();
                while (await reader.ReadAsync())
                {
                    var row = new Dictionary<string, object>();
                    for (int i = 0; i < reader.FieldCount; i++)
                    {
                        row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                    }
                    results.Add(row);
                }

                _logger.LogInformation(
                    "Query executed successfully. CorrelationId: {CorrelationId}, RowCount: {RowCount}",
                    correlationId,
                    results.Count);
            }
            catch (SqlException ex)
            {
                _logger.LogError(
                    ex,
                    "Database query failed. CorrelationId: {CorrelationId}, SqlError: {SqlError}, State: {State}, " +
                    "ErrorNumber: {ErrorNumber}, SanitizedMessage: {SanitizedMessage}",
                    correlationId,
                    ex.Number,
                    ex.State,
                    ex.Number,
                    LogSanitizer.SanitizeExceptionMessage(ex.Message));
                throw;
            }

            return results;
        }
    }

