                    if (customerRequest.SearchTerm.Length > 200)
                    {
                        return new BadRequestObjectResult(new { error = "Search term too long.", correlationId });
                    }

                    query = "SELECT TOP 50 Id, Name, CreatedDate, Status FROM Customers WHERE Name LIKE @SearchTerm";
                    queryParams["@SearchTerm"] = $"%{customerRequest.SearchTerm}%";
