                        "Type: {ExceptionType}, SanitizedMessage: {SanitizedMessage}",
                        depth,
                        correlationId,
                        innerEx.GetType().FullName,
                        LogSanitizer.SanitizeExceptionMessage(innerEx.Message));
                    innerEx = innerEx.InnerException;
                    depth++;
                }

                // Return generic error to client — never expose internal details
                return new ObjectResult(new
                {
                    error = "An internal error occurred. Please contact support with the correlation ID.",
                    correlationId
                })
                {
                    StatusCode = StatusCodes.Status500InternalServerError
                };
