        /// <summary>
        /// Validates customer ID against an allowlist pattern (alphanumeric, hyphens, max 50 chars).
        /// </summary>
        private static bool IsValidCustomerId(string customerId)
        {
            if (string.IsNullOrWhiteSpace(customerId) || customerId.Length > 50)
                return false;

            return Regex.IsMatch(customerId, @"^[a-zA-Z0-9\-]+$");
        }
